// Extract and clean the raw email fields only — prompt lives in the AI node
const email = $input.first().json;

function stripHtml(html) {
  return (html || '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();
}

function removeQuotedText(text) {
  const markers = [
    /\nOn .+?wrote:/s,
    /\n-{3,}/,
    /\nFrom:\s+/,
    /\n_{3,}/,
    /\n>{1,}/m
  ];
  let result = text || '';
  for (const marker of markers) {
    const idx = result.search(marker);
    if (idx > 80) { result = result.substring(0, idx); break; }
  }
  return result.trim();
}

// Gmail trigger returns capitalized headers: From, To, Subject, Date
// Body: prefer full text/html, fall back to snippet
const rawBody   = email.text || email.Text || stripHtml(email.html || email.Html || '') || email.snippet || '';
const cleanBody = removeQuotedText(rawBody).substring(0, 3500);

const fromRaw   = email.From || email.from || '';
const fromMatch = fromRaw.match(/^(.+?)\s*<([^>]+)>$/);
const fromName  = fromMatch ? fromMatch[1].replace(/"/g, '').trim() : fromRaw.split('@')[0];
const fromEmail = fromMatch ? fromMatch[2].trim() : fromRaw.trim();

return [{
  json: {
    from:      fromEmail,
    fromName,
    subject:   email.Subject  || email.subject  || '(no subject)',
    date:      email.Date     || email.date      || new Date().toISOString(),
    threadId:  email.threadId || '',
    messageId: email.id       || '',
    toAddress: email.To       || email.to        || '',
    cleanBody
  }
}];

// ── Parse the AI JSON response and merge with original email data ───────────
const llmOutput  = $input.first().json;
const emailData  = $('Prepare Email Data').first().json;

// The LLM Chain can surface the text under different keys depending on n8n version
const llmText = llmOutput.output || llmOutput.text || llmOutput.response || '';

let parsed;
try {
  // Robustly extract the first JSON object from the response
  // (handles cases where the model adds commentary before/after)
  const jsonMatch = llmText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON object found in AI response');
  parsed = JSON.parse(jsonMatch[0]);

  // Validate required fields
  const validCategories = ['Spam', 'Sales Lead', 'Tech Support', 'FAQ', 'Billing', 'Other'];
  const validPriorities  = ['Low', 'Medium', 'High', 'Urgent'];
  if (!validCategories.includes(parsed.category)) parsed.category = 'Other';
  if (!validPriorities.includes(parsed.priority))  parsed.priority = 'Medium';

} catch (e) {
  // Graceful fallback — the draft will still be created for human review
  parsed = {
    category:    'Other',
    priority:    'Medium',
    summary:     'AI parsing failed — please review this email manually.',
    sentiment:   'Neutral',
    language:    'English',
    draft_reply: 'Thank you for contacting us. A member of our team will review your message and respond as soon as possible.\n\nBest regards,\n[YOUR NAME]'
  };
}

return [{
  json: {
    // Original email fields
    from:        emailData.from,
    fromName:    emailData.fromName,
    subject:     emailData.subject,
    date:        emailData.date,
    threadId:    emailData.threadId,
    messageId:   emailData.messageId,
    toAddress:   emailData.toAddress,
    // AI triage results
    category:    parsed.category,
    priority:    parsed.priority,
    summary:     parsed.summary    || '',
    sentiment:   parsed.sentiment  || 'Neutral',
    language:    parsed.language   || 'English',
    draft_reply: parsed.draft_reply || '',
    // Metadata
    processedAt: new Date().toISOString(),
    rawAiText:   llmText
  }
}];

